import{_ as n,r as i,o as r,c,b as t,d as e,e as a,a as o}from"./app-2a089349.js";const l={},h=o('<h1 id="test-your-integration-with-stripe-test-clocks" tabindex="-1"><a class="header-anchor" href="#test-your-integration-with-stripe-test-clocks" aria-hidden="true">#</a> Test your integration with Stripe test clocks</h1><p>Ultimate Member Stripe extension integrates the stripe checkout page, and customer billing features, allowing users to pay, subscribe, and manage plans. Once you set up this extension, you must test its integrity.</p><p>Before testing your integration, make sure you&#39;ve read and set the required details in the following documentation before you proceed:</p><ul><li><a href="/docs-v3/um-stripe/article/1607-stripe-setting-up-webhook-and-test-public-keys">Setting up Webhook and Test/Public Keys</a></li><li><a href="/docs-v3/um-stripe/article/1609-stripe---setting-up-stripe-success-and-cancel-payment-pages">Setting up Stripe Success and Cancel Payment Pages</a></li><li><a href="/docs-v3/um-stripe/article/1617-create-subscription-prices">Create Subscription Prices</a></li><li><a href="/docs-v3/um-stripe/article/1616-stripe-shortcodes-reference">Shortcodes &amp; Subscription Events</a></li><li><a href="/docs-v3/um-stripe/article/1634-stripe---add-subscription-plans-to-a-registeration-form">Add Subscription Plans to a Register Form</a></li><li><a href="/docs-v3/um-stripe/article/1611-stripe---create-test-customer-billings">Create &amp; Test Customer Billings</a></li></ul>',4),g=t("strong",null,"Note:",-1),u=t("strong",null,"/?umm-stripe-webhook=true",-1),d={href:"http://localhost:4242/?umm-stripe-webhook=true",target:"_blank",rel:"noopener noreferrer"},p=t("p",null,[e("To learn more about the Stripe CLI, please see this doc article: "),t("a",{href:"/docs-v3/um-stripe/article/1864-stripe-cli-integration"},"/docs-v3/um-stripe/article/1864-stripe-cli-integration")],-1),m=t("strong",null,"Stripe Test Clocks",-1),b={href:"https://stripe.com/docs/billing/testing/test-clocks",target:"_blank",rel:"noopener noreferrer"},f=o('<p>To see if the integration is working we suggest you create roles in <strong>wp-admin&gt; Ultimate Member&gt; User Roles</strong> so you can set in <strong>wp-admin&gt;Ultimate Member&gt; Stripe Plans&gt; Edit a plan</strong> and see what happens when a subscription is active, unpaid, paused, past due, canceled or trialing.</p><p><img src="https://s3.amazonaws.com/helpscout.net/docs/assets/561c96629033600a7a36d662/images/65b421b252a6af5def3c8e25/file-IRrkB2qEHu.png" alt=""></p><h3 id="testing-integration-with-stripe-test-clocks" tabindex="-1"><a class="header-anchor" href="#testing-integration-with-stripe-test-clocks" aria-hidden="true">#</a> Testing Integration with Stripe Test Clocks</h3><p>To effectively test your integration with Stripe Test Clocks, follow the steps outlined below:</p><h4 id="_1-setup-test-environment" tabindex="-1"><a class="header-anchor" href="#_1-setup-test-environment" aria-hidden="true">#</a> 1. Setup Test Environment</h4>',5),w={href:"https://dashboard.stripe.com/test/dashboard",target:"_blank",rel:"noopener noreferrer"},y=t("img",{src:"https://s3.amazonaws.com/helpscout.net/docs/assets/561c96629033600a7a36d662/images/65b4cbd352a6af5def3c8e6a/file-aFZCoxOGLn.png",alt:""},null,-1),k=t("h4",{id:"_2-create-a-test-clock",tabindex:"-1"},[t("a",{class:"header-anchor",href:"#_2-create-a-test-clock","aria-hidden":"true"},"#"),e(),t("strong",null,"2. Create a Test Clock")],-1),v=t("li",null,[e("Go to the "),t("strong",null,"'Billing'"),e(" tab and click on the '"),t("strong",null,"Quick actions'"),e(" button"),t("strong",null,".")],-1),_=t("li",null,[e("Click on the '"),t("strong",null,"Create simulation'"),t("br"),t("img",{src:"https://s3.amazonaws.com/helpscout.net/docs/assets/561c96629033600a7a36d662/images/65b6256152a6af5def3c8e7d/file-ifsMHRajuB.png",alt:""})],-1),C={href:"https://dashboard.stripe.com/test/billing/subscriptions/test-clocks",target:"_blank",rel:"noopener noreferrer"},S=t("strong",null,"'+New simulation'",-1),T=t("strong",null,[t("img",{src:"https://s3.amazonaws.com/helpscout.net/docs/assets/561c96629033600a7a36d662/images/65b62dd230c1875e8e06758a/file-QK5z3vhtHk.png",alt:""})],-1),z=t("li",null,[e("Set a simulation name and the starting date and time of your simulation. Then click on the "),t("strong",null,"'Create'"),e(" button, you may be presented with a security check when you click the button. "),t("img",{src:"https://s3.amazonaws.com/helpscout.net/docs/assets/561c96629033600a7a36d662/images/65b6305930c1875e8e06758c/file-R9RN3neV6t.png",alt:""})],-1),x=t("li",null,[e("Once created, copy the "),t("strong",null,"Test Clock ID"),e(" in the upper right corner."),t("br"),t("img",{src:"https://s3.amazonaws.com/helpscout.net/docs/assets/561c96629033600a7a36d662/images/65b632be20e3b82eb738e0d8/file-Y9UBd3fQB5.png",alt:""})],-1),P=o('<h4 id="_3-configure-ultimate-member-settings" tabindex="-1"><a class="header-anchor" href="#_3-configure-ultimate-member-settings" aria-hidden="true">#</a> 3. Configure Ultimate Member Settings</h4><ul><li>Go to <strong>wp-admin&gt;Ultimate Member&gt; Settings&gt; Extension&gt;Stripe</strong></li><li>Enable <strong>Sandbox/Test Mode</strong> setting.</li><li>Enable the Test Clock and paste the <strong>Test Clock ID</strong> in the field. This will create a Stripe customer for the Test clock</li><li>Click the &#39;<strong>Save Changes&#39;</strong> button<br><img src="https://s3.amazonaws.com/helpscout.net/docs/assets/561c96629033600a7a36d662/images/65b646551280097516451b44/file-sawyZiCffy.png" alt=""></li></ul><h4 id="_4-setup-your-testing-simulation" tabindex="-1"><a class="header-anchor" href="#_4-setup-your-testing-simulation" aria-hidden="true">#</a> <strong>4. Setup your Testing Simulation</strong></h4><ul><li><p>Create a user in <strong>wp-admin &gt; Users</strong>. After creating the user, you can verify that the user is in Test Clock mode in the Subscription status. <img src="https://s3.amazonaws.com/helpscout.net/docs/assets/561c96629033600a7a36d662/images/65b64b3752a6af5def3c8e82/file-FEGsDkRRyF.png" alt=""></p></li><li><p>Go back to the <strong>Stripe Dashboard &gt; Subscription &gt; Test clocks</strong>. Choose the test clocks simulation you created earlier by clicking on it.<br><img src="https://s3.amazonaws.com/helpscout.net/docs/assets/561c96629033600a7a36d662/images/65b64ed120e3b82eb738e0db/file-YNawpmrHnM.png" alt=""></p></li><li><p>Find the customer or user you created in wp-admin &gt; Users in the Clock Objects section. Confirm and ensure that the customer email matches the one registered on your site. <img src="https://s3.amazonaws.com/helpscout.net/docs/assets/561c96629033600a7a36d662/images/65b6517e52a6af5def3c8e83/file-m2pH7azLaY.png" alt=""></p><p><strong>Note: When creating a customer in wp-admin&gt;Users, the customer will only appear in test clocks if the Test Clocks option is enabled and the test clock ID is entered in wp-admin&gt;Ultimate Member&gt;Settings&gt;Extensions&gt;Stripe. Therefore, it is important to enable these settings before creating a user.</strong></p></li></ul><h4 id="_5-execute-test-cases" tabindex="-1"><a class="header-anchor" href="#_5-execute-test-cases" aria-hidden="true">#</a> 5. Execute Test Cases</h4>',5),U={href:"https://stripe.com/docs/billing/testing/test-clocks#how-to-use-test-clocks",target:"_blank",rel:"noopener noreferrer"},I=o('<li><h5 id="trial-subscription" tabindex="-1"><a class="header-anchor" href="#trial-subscription" aria-hidden="true">#</a> <strong>Trial &amp; Subscription</strong></h5><ul><li>Follow the steps above on how to create a customer then login to your site in another browser using the logins of the customer you&#39;ve created. <img src="https://s3.amazonaws.com/helpscout.net/docs/assets/561c96629033600a7a36d662/images/65b675ba20e3b82eb738e0ea/file-sQM28qIobK.png" alt=""></li><li>Then go to the page where you added the subscription plans and select or click the subscribed button that links to the Stripe Plan you&#39;ve set up with a free trial. <img src="https://s3.amazonaws.com/helpscout.net/docs/assets/561c96629033600a7a36d662/images/65b67a7d1280097516451b53/file-f5RyIjCw8Z.png" alt=""></li><li>Enter the payment details. For testing, you can use this Credit Card Number <strong>4242 4242 4242 4242</strong>. For the Year and Month, use <strong>4/42</strong>; for the CCV, use <strong>424</strong>. Then click on the &#39;<strong>Start trial&#39;</strong> button. Once the subscription is successful, you&#39;ll get redirected to the Stripe success page of your site. <img src="https://s3.amazonaws.com/helpscout.net/docs/assets/561c96629033600a7a36d662/images/65b684b830c1875e8e06759e/file-qiVtD7uRTm.png" alt=""></li><li>Now go to your <strong>Stripe Dashboard&gt;Billing&gt; Subscription&gt; Test clocks&gt;</strong> Select your test clocks simulation and click on the user with the trial subscription.<br><img src="https://s3.amazonaws.com/helpscout.net/docs/assets/561c96629033600a7a36d662/images/65b685dc52a6af5def3c8e97/file-2KuSDfvW2q.png" alt=""></li><li>You&#39;ll see in the customer&#39;s overview that the subscription is on trial, and then in the <strong>invoices</strong> section, you&#39;ll see that an <strong>invoice of $0.00</strong> is generated due to the free trial. <img src="https://s3.amazonaws.com/helpscout.net/docs/assets/561c96629033600a7a36d662/images/65b6874152a6af5def3c8e98/file-NBwLbzJgBV.png" alt=""></li><li>Go to <strong>wp-admin&gt;Users</strong> and check if the role and the status have changed to Trialing. <img src="https://s3.amazonaws.com/helpscout.net/docs/assets/561c96629033600a7a36d662/images/65b68a2230c1875e8e06759f/file-LtsPAzBJj9.png" alt=""></li></ul></li>',1),B=t("h5",{id:"pause-resume",tabindex:"-1"},[t("a",{class:"header-anchor",href:"#pause-resume","aria-hidden":"true"},"#"),e(" Pause & Resume")],-1),M=o('<li><p>Pause</p><ul><li>Switch to the other browser where you have a user account with a trial subscription. If you&#39;re currently on the payment success page, you can click on the Customer Portal button. <img src="https://s3.amazonaws.com/helpscout.net/docs/assets/561c96629033600a7a36d662/images/65b6907520e3b82eb738e0f0/file-nSsGf6U2XZ.png" alt=""></li><li>If you&#39;re not on the payment success page anymore, navigate to the page <a href="/docs-v3/um-stripe/article/1894-how-to-access-the-stripe-customer-portal-from-the-website"> where you added the Customer Portal shortcode</a> . Once you&#39;re on that page, click the <a href="/docs-v3/um-stripe/article/1611-stripe---create-test-customer-billings">&quot;Manage billing&quot;</a> button to manage your billing. This button will automatically redirect you to the Stripe Customer Billing/Portal page. <img src="https://s3.amazonaws.com/helpscout.net/docs/assets/561c96629033600a7a36d662/images/65b691d930c1875e8e0675a2/file-CvdeoTjilQ.png" alt=""></li><li>Click on the <strong>Cancel Plan</strong> button. You&#39;ll be redirected to <strong>Billing&gt;Cancel or Pause</strong>. Under the current plan, select <strong>Pause Subscription</strong>, and click the <strong>Pause Plan</strong> button.<br><img src="https://s3.amazonaws.com/helpscout.net/docs/assets/561c96629033600a7a36d662/images/65b6937c1280097516451b55/file-svyJjhdpzb.png" alt=""></li><li>Take notice that in this example, the Plan Subscription will automatically renew after <strong>one month;</strong> therefore, we&#39;ll test it using the test clock.</li><li>Go to Stripe Dashboard&gt; Billings&gt; &gt;Subscription&gt;Test Clocks&gt; Select your test clocks simulation&gt; click on the customer with a <strong>paused plan.</strong> You&#39;ll see in the customer&#39;s <strong>Overview&gt; Subscriptions</strong> that the collection is paused. <img src="https://s3.amazonaws.com/helpscout.net/docs/assets/561c96629033600a7a36d662/images/65b6944830c1875e8e0675a3/file-3aJ8UzYRs6.png" alt=""></li><li>Go to <strong>wp-admin&gt;Users</strong> and check if the role and status have changed. <img src="https://s3.amazonaws.com/helpscout.net/docs/assets/561c96629033600a7a36d662/images/65b69dc930c1875e8e0675a8/file-gKthr0vqzU.png" alt=""></li></ul></li><li><h5 id="resume" tabindex="-1"><a class="header-anchor" href="#resume" aria-hidden="true">#</a> Resume</h5><ul><li>On the customer&#39;s page in Stripe, you will find a banner at the top with an <strong>&#39;Advance Time&#39;</strong> button. Simply click on this button.<br><img src="https://s3.amazonaws.com/helpscout.net/docs/assets/561c96629033600a7a36d662/images/65b695b052a6af5def3c8e99/file-FgOA5P5AoN.png" alt=""></li><li>As we mentioned earlier, the resume time of the subscription paused plan is after 1 month, so we&#39;ll advance the time to a month. The clock time date is <strong>January 28, 2024,</strong> so we&#39;ll advance it to <strong>February 28, 2024,</strong> or you can select <strong>&quot;+1 month&quot;</strong> from the shortcut. Once you&#39;ve selected the date, click on the <strong>Advance</strong> button. <img src="https://s3.amazonaws.com/helpscout.net/docs/assets/561c96629033600a7a36d662/images/65b696dc30c1875e8e0675a4/file-dRVFwtntPP.png" alt=""></li><li>The clock time has advanced and the customer subscription plan has now resumed, you can see it in the customer&#39;s subscription overview. The subscription becomes active because the plan has been resumed. You can see in the Payments and Invoices that the payment for the 1st month was <strong>canceled</strong> and <strong>void</strong> because the subscription plan was <strong>paused</strong>. <img src="https://s3.amazonaws.com/helpscout.net/docs/assets/561c96629033600a7a36d662/images/65b6995d52a6af5def3c8e9b/file-LdlCKOi3CE.png" alt=""></li><li>Go to <strong>wp-admin&gt; Users</strong> and check if the role and status have changed. The subscription status has been active again. <img src="https://s3.amazonaws.com/helpscout.net/docs/assets/561c96629033600a7a36d662/images/65b69a1230c1875e8e0675a7/file-8ACNkZrYUm.png" alt=""></li></ul></li><li><p><strong>Canceled</strong></p><ul><li>To test the cancel integration, log in to your site in another browser using the customer&#39;s account with an <strong>active subscription,</strong> then go to the page where you&#39;ve added the <strong>Customer Billing Portal</strong> shortcode and click on the <strong>Manage billing</strong> button. <img src="https://s3.amazonaws.com/helpscout.net/docs/assets/561c96629033600a7a36d662/images/65b691d930c1875e8e0675a2/file-CvdeoTjilQ.png" alt=""></li><li>Click on the <strong>Cancel Plan</strong> button. You&#39;ll be redirected to <strong>Billing&gt;Cancel or Pause</strong>. Under the current plan, select the <strong>Cancel subscription,</strong> then click the <strong>Cancel plan</strong> button.<br><img src="https://s3.amazonaws.com/helpscout.net/docs/assets/561c96629033600a7a36d662/images/65b69c9a1280097516451b57/file-NkywQgu6w7.png" alt=""></li><li>In the customer&#39;s <strong>Overview&gt; Subscriptions and</strong> Payments the subscription is <strong>canceled</strong>.<br><img src="https://s3.amazonaws.com/helpscout.net/docs/assets/561c96629033600a7a36d662/images/65b69ed51280097516451b58/file-0D8HhHV1Fe.png" alt=""></li><li>Go to wp-admin&gt;Users and check if the role and status have changed. <img src="https://s3.amazonaws.com/helpscout.net/docs/assets/561c96629033600a7a36d662/images/65b69f4730c1875e8e0675a9/file-DCsQaTTK5X.png" alt=""></li></ul></li><li><h5 id="past-due" tabindex="-1"><a class="header-anchor" href="#past-due" aria-hidden="true">#</a> Past Due</h5><ul><li>Log in to your site in another browser using the customer&#39;s account you&#39;ve created in <strong>wp-admin&gt;Users</strong>. Then go to the page where you added the subscription plans. Subscribe to the plan with a free trial using these payment details: Credit Card Number <strong>4000 0000 0000 3220</strong>, expiring <strong>3/24</strong>, and CCV <strong>232</strong>. <img src="https://s3.amazonaws.com/helpscout.net/docs/assets/561c96629033600a7a36d662/images/65b67a7d1280097516451b53/file-f5RyIjCw8Z.png" alt=""> <img src="https://s3.amazonaws.com/helpscout.net/docs/assets/561c96629033600a7a36d662/images/65b6a260270765339befc78b/file-KfbgkkEtzY.png" alt=""></li><li>A 3D secure popup window will appear. To continue, click the <strong>&quot;Complete&quot;</strong> button.</li><li>Once the Subscription Trial is Active, go to Stripe dashboard&gt;Customers&gt; click on the <strong>customer with an active trial subscription.</strong> You will see in the customer&#39;s overview&gt;subscriptions that the subscription status is in <strong>Trial mode</strong> and will end on <strong>March 2. <img src="https://s3.amazonaws.com/helpscout.net/docs/assets/561c96629033600a7a36d662/images/65b6a4fd1280097516451b5a/file-L72TAnONyw.png" alt=""></strong></li><li>Click on the <strong>&#39;</strong><strong>Advance time&#39;</strong> button and set the clock to the day after the end date of the trial. In this example, we have set the time to <strong>March</strong> <strong>3</strong>. Click the <strong>&#39;Advance &#39;</strong> button after setting up the date and time. <img src="https://s3.amazonaws.com/helpscout.net/docs/assets/561c96629033600a7a36d662/images/65b6a5a6270765339befc78c/file-LehqQjUGFc.png" alt=""></li><li>Once the clock time has been advanced, the payment failed, the customer was not charged because the card is declined, so the status will be <strong>Past Due. <img src="https://s3.amazonaws.com/helpscout.net/docs/assets/561c96629033600a7a36d662/images/65b6a745270765339befc78e/file-hoKzQMaQpw.png" alt=""></strong></li><li>You can check in <strong>wp-admin&gt; Users</strong> if the role and status have changed. <img src="https://s3.amazonaws.com/helpscout.net/docs/assets/561c96629033600a7a36d662/images/65b6a7cc30c1875e8e0675ac/file-fGGvatnohA.png" alt=""></li></ul></li>',4),N=t("p",null,[t("strong",null,"Unpaid")],-1),R=t("li",null,[e("If all retries scheduled for the customer's subscription payment have failed instead of "),t("strong",null,"canceled subscription status"),e(", you can change the settings and turn it into an "),t("strong",null,"unpaid subscription status"),e(".")],-1),Y={href:"https://dashboard.stripe.com/settings/billing/automatic",target:"_blank",rel:"noopener noreferrer"},A=t("strong",null,"Manage failed payments> Subscription status > If all retries for a payment fail > Mark the subscription unpaid.",-1),E=t("strong",null,[t("img",{src:"https://s3.amazonaws.com/helpscout.net/docs/assets/561c96629033600a7a36d662/images/65b6a9b71280097516451b5b/file-jAKiOK3EHk.png",alt:""})],-1),G=o('<li>Log in to your site in another browser using a test customer&#39;s account you&#39;ve created in <strong>wp-admin&gt;Users</strong>. Then go to the page where you&#39;ve added the subscription plans and subscribe to a plan with a free trial using these payment details: <strong>Credit Card Number:</strong> <strong>4000000000000341, exp: 3/24 CCV: 232<br><img src="https://s3.amazonaws.com/helpscout.net/docs/assets/561c96629033600a7a36d662/images/65b67a7d1280097516451b53/file-f5RyIjCw8Z.png" alt=""> <img src="https://s3.amazonaws.com/helpscout.net/docs/assets/561c96629033600a7a36d662/images/65b6ad58270765339befc78f/file-1fbCWSCtfi.png" alt=""></strong></li><li>In Stripe Dashboard, Go to the <strong>Customers tab&gt; Click on the customer with an active trial subscription</strong>. <img src="https://s3.amazonaws.com/helpscout.net/docs/assets/561c96629033600a7a36d662/images/65b6ade41280097516451b5c/file-1JLE3FGXcs.png" alt=""></li><li>You will see that the subscription status is in Trial mode and will end on <strong>March 6.</strong> Click on the <strong>&#39;Advance time&#39;</strong> button and set the clock to the day after the end date of the trial. <img src="https://s3.amazonaws.com/helpscout.net/docs/assets/561c96629033600a7a36d662/images/65b6afb430c1875e8e0675ad/file-DQ1xJSN4QV.png" alt=""></li><li>In this example, we have set the date to <strong>March 7, 2023</strong>. The subscription is now <strong>Past due</strong> because of the failed payment, so the invoice shows that it&#39;s retrying. <img src="https://s3.amazonaws.com/helpscout.net/docs/assets/561c96629033600a7a36d662/images/65b6b0e930c1875e8e0675ae/file-6SFNf88sHf.png" alt=""></li><li>The charge retry schedule will be displayed if you hover your mouse over the <strong>Retrying</strong> notice <img src="https://s3.amazonaws.com/helpscout.net/docs/assets/561c96629033600a7a36d662/images/65b6b14830c1875e8e0675af/file-KOPs80qbLA.png" alt=""></li><li>You&#39;ll get the <strong>Unpaid subscription</strong> status <strong>after 3 to 7 retries of failed payment charges</strong>. To test, keep advancing the time after the scheduled invoice date. The images below show the events for which we advanced the time and date multiple times and got the unpaid subscription status when we advanced the time/date to <strong>April 10,</strong> a month after the scheduled invoice<strong>(March 7) <img src="https://s3.amazonaws.com/helpscout.net/docs/assets/561c96629033600a7a36d662/images/65b6b34320e3b82eb738e0f9/file-jjPwQNp5Zn.png" alt=""></strong></li><li>If you scroll down to the <strong>&#39;Recent Activity&#39;</strong> section, you&#39;ll find here the multiple failed payments. <img src="https://s3.amazonaws.com/helpscout.net/docs/assets/561c96629033600a7a36d662/images/65b6b3ee30c1875e8e0675b0/file-qdC8sQ16YD.png" alt=""></li><li>In the <strong>Events and Logs</strong> tab, you can also see in the <strong>Events</strong> the failed attempts of payments. <img src="https://s3.amazonaws.com/helpscout.net/docs/assets/561c96629033600a7a36d662/images/65b6b58230c1875e8e0675b3/file-vGys1Lxa9e.png" alt=""></li><li>You can check in <strong>wp-admin&gt;Users</strong> if the role and status have changed. <img src="https://s3.amazonaws.com/helpscout.net/docs/assets/561c96629033600a7a36d662/images/65b6b62052a6af5def3c8ea8/file-eRPhTw0evY.png" alt=""></li>',9);function L(D,O)